// The debounce function is used to delay the execution of a function, typically used with events triggered frequently, to prevent unnecessary repeated execution.

function debounce (func, timeout = 500) {
    let timeoutId;
    return (...args) => {
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => func.apply(this, args), timeout);
    };
}

// Example usage:
const sayHello = debounce(function(name) {
    console.log(`Hello, ${name}!`);
});
sayHello('John'); // Creates a debounced function that logs 'Hello, John!' after 500ms
